import React, { useState } from "react";
import "./style.css";
import MenuIcon from '@mui/icons-material/Menu';
import Sidebar from "../sidebar/Sidebar";
import { FaBars } from "react-icons/fa";
import Switch from "react-switch";

const Header = () => {
   const [collased, setCollased] = useState(false);
   const [image, setImage] = useState(false);
   const [toggle, setToggle] = useState(false);
   const handleCollasedChange = () => {
     setCollased(!collased);
   };
  
   const handleToggleSidebar = (value) => {
     setToggle(value);
   };


  return (
    <>
      <nav className="nav_container">
        <Sidebar
          image={image}
          toggle={toggle}
          handleToggleSidebar={handleToggleSidebar}
          handleCollasedChange={handleCollasedChange}
        />
        <div className="nav_subconatainer_1">
          <button
            onClick={() => handleToggleSidebar(true)}
            className="menu_box"
          >
            <FaBars />
          </button>
          <div className="logo_box">
            <img className="logo" src="er" alt="logo" />
          </div>
          <div className="text_box">
            <span className="text">Logo</span>
          </div>
        </div>
        <div className="nav_subconatainer_2">
          <input type="search" placeholder="Search" className="search_box" />
        </div>
        <div className="nav_subconatainer_3">
          <ul className="nav_ul">
            <li className="nav_li">
              <a href="#5">Login</a>
            </li>
            <li className="nav_li">
              <a href="#5">SignUp</a>
            </li>
          </ul>
        </div>
        <Switch
          height={16}
          width={30}
          checkedIcon={false}
          uncheckedIcon={false}
          onChange={handleImageChange}
          checked={image}
          onColor="#219de9"
          offColor="#bbbbbb"
        />
      </nav>
    </>
  );
};

export default Header;
